 33â†’private fun <E : Throwable> createConstructor(clz: Class<E>): Ctor {
 34â†’    val nullResult: Ctor = { null } // Pre-cache class
 35â†’    // Skip reflective copy if an exception has additional fields (that are usually populated in user-defined constructors)
 36â†’    if (throwableFields != clz.fieldsCountOrDefault(0)) return nullResult
 37â†’    /*
 38â†’    * Try to reflectively find constructor(), constructor(message, cause), constructor(cause) or constructor(message).
 39â†’    * Exceptions are shared among coroutines, so we should copy exception before recovering current stacktrace.
 40â†’    */
 41â†’    val constructors = clz.constructors.sortedByDescending { it.parameterTypes.size }
 42â†’    for (constructor in constructors) {
 43â†’        val result = createSafeConstructor(constructor)
 44â†’        if (result != null) return result
 45â†’    }
 46â†’    return nullResult
