 49â†’private fun createSafeConstructor(constructor: Constructor<*>): Ctor? {
 50â†’    val p = constructor.parameterTypes
 51â†’    return when (p.size) {
 52â†’        2 -> when {
 53â†’            p[0] == String::class.java && p[1] == Throwable::class.java ->
 54â†’                safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
 55â†’            else -> null
 56â†’        }
 57â†’        1 -> when (p[0]) {
 58â†’            Throwable::class.java ->
 59â†’                safeCtor { e -> constructor.newInstance(e) as Throwable }
