 91â†’        cacheLock.read { exceptionCtors[key]?.let { return it } }
 92â†’        cacheLock.write {
 93â†’            exceptionCtors[key]?.let { return it }
 94â†’            return createConstructor(key).also { exceptionCtors[key] = it }
 95â†’        }
 96â†’    }
 97â†’}
