101â†’    private val cache = object : ClassValue<Ctor>() {
102â†’        override fun computeValue(type: Class<*>?): Ctor {
103â†’            @Suppress("UNCHECKED_CAST")
104â†’            return createConstructor(type as Class<out Throwable>)
105â†’        }
106â†’    }
107â†’
